public class ConstraintViolationSummary { public String constrainClass ; public short violationCode ; public String violationDescription ; public long numberOfViolatingMutations ; public ConstraintViolationSummary ( String constrainClass , short violationCode , String violationDescription , long numberOfViolatingMutations ) { this . constrainClass = constrainClass ; this . violationCode = violationCode ; this . violationDescription = violationDescription ; this . numberOfViolatingMutations = numberOfViolatingMutations ; } public ConstraintViolationSummary ( TConstraintViolationSummary tcvs ) { this ( tcvs . constrainClass , tcvs . violationCode , tcvs . violationDescription , tcvs . numberOfViolatingMutations ) ; } public String getConstrainClass ( ) { return this . constrainClass ; } public short getViolationCode ( ) { return this . violationCode ; } public String getViolationDescription ( ) { return this . violationDescription ; } public long getNumberOfViolatingMutations ( ) { return this . numberOfViolatingMutations ; } @ Override public String toString ( ) { return String . format ( "ConstraintViolationSummary(constrainClass:%s, violationCode:%d, violationDescription:%s, numberOfViolatingMutations:%d)" , constrainClass , violationCode , violationDescription , numberOfViolatingMutations ) ; } public TConstraintViolationSummary toThrift ( ) { return new TConstraintViolationSummary ( this . constrainClass , violationCode , violationDescription , numberOfViolatingMutations ) ; } }